sys_script_include.script:
var WaitTimeComputationOfQueue = Class.create();
WaitTimeComputationOfQueue.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {

    queueTable: sn_walkup.WalkUpConstants.INTERACTION_TABLE,
    queueId: '',

    getArrivalRate: function() {

        var workItem = new GlideRecord('awa_work_item');
        workItem.addQuery('queue', this.queueId);
        //workItem.addQuery('state', 'queued').addOrCondition('state', 'pending_accept');
		workItem.addQuery('sys_created_onONToday@javascript:gs.beginningOfToday()@javascript:gs.endOfToday()');
        workItem.addQuery('active', 'true');
        workItem.setCategory("walkup_meta");
        workItem.query();

        var records = [];
        while (workItem.next()) {
            var record = {
                number: workItem.getValue('number'),//workItem.document_id.number,
                sysId: workItem.getUniqueValue(),
                createdTimestamp: new GlideDateTime(workItem.sys_created_on.getDisplayValue()).getNumericValue()
            };
            records.push(record);
        }

        // Sort records by creation timestamp
        records.sort(function(a, b) {
            return a.createdTimestamp - b.createdTimestamp;
        });

        var interarrivalTimes = [];
        var previousCreatedTime = null;

        // Loop to compute interarrival times
        for (var i = 0; i < records.length; i++) {
            var currentCreatedTime = records[i].createdTimestamp;

            // Calculate interarrival time
            if (previousCreatedTime !== null) {
                var interarrivalTime = currentCreatedTime - previousCreatedTime;
                interarrivalTimes.push(interarrivalTime / 60000); // Convert milliseconds to minutes
            }

            previousCreatedTime = currentCreatedTime;
        }

        // Handle cases where no valid interarrival times were collected
        if (interarrivalTimes.length === 0) {
            gs.error('No valid interarrival times found.');
            return {
                arrivalRate: 0 // No valid arrival rate
            };
        }

        // Calculate arrival rate
        var meanInterarrivalTime = this.calculateMean(interarrivalTimes);
        var arrivalRate = meanInterarrivalTime > 0 ? 1 / meanInterarrivalTime : 0; // Prevent division by zero

        return {
            arrivalRate: arrivalRate
        };
    },


    getServiceRate: function() {
        var workItem = new GlideRecord('awa_work_item');
        workItem.addEncodedQuery('state=cancelled^ORstate=accepted');
		workItem.addEncodedQuery('sys_created_onONToday@javascript:gs.beginningOfToday()@javascript:gs.endOfToday()');
        workItem.addQuery('active', 'true');
        workItem.setCategory("walkup_meta");
        workItem.query();

        var records = [];
        while (workItem.next()) {

            var record = {
                number: workItem.getValue('number'),// workItem.document_id.number,
                sysId: workItem.getUniqueValue(),
                createdTimestamp: new GlideDateTime(workItem.sys_created_on.getDisplayValue()).getNumericValue(),
                closedTimestamp: workItem.sys_updated_on ? new GlideDateTime(workItem.sys_updated_on.getDisplayValue()).getNumericValue() : null // Check if sys_updated_on exists
            };
            records.push(record);
        }
        // Sort records by creation timestamp
        records.sort(function(a, b) {
            return a.createdTimestamp - b.createdTimestamp;
        });

        var serviceTimes = [];
        // Loop to compute service times
        for (var i = 0; i < records.length; i++) {
            var createdTimestamp = records[i].createdTimestamp;
            var closedTimestamp = records[i].closedTimestamp;
            // Calculate service time (if closedTimestamp exists)
            if (closedTimestamp) {

                var totalElapsedTime = closedTimestamp - createdTimestamp;
                serviceTimes.push(totalElapsedTime / 60000); // Convert milliseconds to minutes
            }
        }
        // Handle cases where no valid service times were collected
        if (serviceTimes.length === 0) {
            gs.error('No valid service times found.');
            return {
                serviceRate: 0 // No valid service rate
            };
        }

        // Calculate service rate
        var meanServiceTime = this.calculateMean(serviceTimes);
        var serviceRate = meanServiceTime > 0 ? 1 / meanServiceTime : 0; // Prevent division by zero
        return {
            serviceRate: serviceRate
        };
    },

    calculateMean: function(data) {
        var sum = data.reduce(function(acc, value) {
            return acc + value;
        }, 0);
        return data.length ? sum / data.length : 0; // Prevent division by zero
    },

    getEstimatedWaitTimeV2: function(numberOfServers, queuePosition) {
        var arrivalRate = this.getArrivalRate().arrivalRate; // tasks per minute
        var serviceRate = this.getServiceRate().serviceRate; // tasks per minute

        if (arrivalRate <= 0 || serviceRate <= 0 || numberOfServers <= 0) {
            gs.warn('Invalid inputs for wait time calculation');
            return {
                waitTimeInQueue: 0,
                status: 'invalid_input'
            };
        }

        var avgWait = this.calculateErlangCWaitTime(arrivalRate, serviceRate, numberOfServers);

        if (!isFinite(avgWait) || avgWait < 0) {
            return {
                waitTimeInQueue: Number.POSITIVE_INFINITY,
                status: 'unstable'
            };
        }

        // additional wait caused by queue position (approximation)
        var extraWait = 0;
        if (queuePosition > 1) {
            var denom = numberOfServers * serviceRate;
            if (denom <= arrivalRate) {
                // defensive: avoid division by zero/negative effective capacity
                extraWait = Number.POSITIVE_INFINITY;
            } else {
                extraWait = (queuePosition - 1) / denom;
            }
        }

        var total = avgWait + extraWait;
        return {
            waitTimeInQueue: Math.round(total), //in Minutes
            components: {
                avgWait: avgWait,
                extraWait: extraWait
            },
            status: 'ok'
        };

    },

    calculateErlangCWaitTime: function(arrivalRate, serviceRate, servers) {
        if (arrivalRate <= 0 || serviceRate <= 0 || servers <= 0) return 0;

        var a = arrivalRate / serviceRate; // offered load (lambda/mu)
        var rho = arrivalRate / (servers * serviceRate); // utilization per server

        if (rho >= 1) {
            gs.warn("Queue unstable: arrival rate >= capacity");
            return Number.POSITIVE_INFINITY;
        }

        // compute sum_{k=0}^{c-1} (a^k)/k! iteratively
        var sum = 1.0;
        var term = 1.0;
        for (var k = 1; k < servers; k++) {
            term = term * a / k; // term = a^k / k!
            sum += term;
        }

        // final term = a^c / c!
        term = term * a / servers;

        // Erlang C
        var denomFactor = (servers - a); // c - a, positive because rho < 1
        var numerator = term * servers / denomFactor;
        var denominator = sum + term * servers / denomFactor;
        var erlangC = numerator / denominator;

        // Wq = ErlangC / (c*mu - lambda)
        var denom = servers * serviceRate - arrivalRate;
        if (denom <= 0) return Number.POSITIVE_INFINITY;
        var waitTime = erlangC / denom;

        return waitTime; // minutes
    },

    getEstimatedWaitTime: function(queue, numberOfServers) {
        queue = this.queueId;
        var arrivalRate = this.getArrivalRate().arrivalRate; // tasks per minute
        var serviceRate = this.getServiceRate().serviceRate; // tasks per minute

        gs.info('ARRIVAL RATE ' + JSON.stringify(arrivalRate));
        gs.info('SERVICE RATE ' + JSON.stringify(serviceRate))
        if (arrivalRate === 0 || serviceRate === 0 || numberOfServers === 0) {
            gs.error('Invalid arrival rate, service rate, or number of servers. Cannot calculate wait time.');
            return {
                waitTimeInQueue: 0
            };
        }

        // Calculate utilization per server
        var utilization = arrivalRate / (numberOfServers * serviceRate);

        // Calculate P0
        var rho = arrivalRate / (numberOfServers * serviceRate);
        var sum = 0;

        // Calculate sum of terms for P0
        for (var k = 0; k < numberOfServers; k++) {
            sum += Math.pow(arrivalRate / serviceRate, k) / this.factorial(k);
        }
        var term = Math.pow(arrivalRate / serviceRate, numberOfServers) / (this.factorial(numberOfServers) * (1 - utilization));
        var P0 = 1 / (sum + term);

        // Calculate Lq
        var Lq = (Math.pow(arrivalRate / serviceRate, numberOfServers) * serviceRate * P0) / (this.factorial(numberOfServers) * Math.pow(1 - utilization, 2));

        // Calculate Wq
        var Wq = Lq / arrivalRate;

        return {
            waitTimeInQueue: Wq
        };
    },

    factorial: function(n) {
        if (n === 0 || n === 1) return 1;
        var result = 1;
        for (var i = 2; i <= n; i++) {
            result *= i;
        }
        return result;
    },

    type: 'WaitTimeComputationOfQueue'
});
